// Round-Robin Agent Assignment Logic
// Assigns agents based on property type from AI agent output

const agentPools = {
  'single-family': [
    'user@example.com',
    'user@example.com'
  ],
  'multi-family': [
    'user@example.com',
    'user@example.com',
    'user@example.com'
  ],
  'condo': [
    'user@example.com',
    'user@example.com',
    'user@example.com'
  ],
  'investment property': [
    'user@example.com',
    'user@example.com',
    'user@example.com'
  ],
  'others': [
    'user@example.com',
    'user@example.com'
  ],
  'default-unassigned': [
    'user@example.com'
  ]
};

// Get incoming item
const item = $input.item.json;

// Read property type (exact field name)
const rawCategory =
  item["What type of property are you interested in?"] ||
  'default-unassigned';

const category = rawCategory
  .trim()
  .toLowerCase()
  .replace(/\s+/g, '-');

// Select agent pool
const agents = agentPools[category] || agentPools['default-unassigned'];

// ✅ Correct way to access static data
const staticData = $getWorkflowStaticData('node');

if (!staticData.agentIndexes) {
  staticData.agentIndexes = {};
}

if (staticData.agentIndexes[category] === undefined) {
  staticData.agentIndexes[category] = 0;
}

// Assign agent
const currentIndex = staticData.agentIndexes[category];
const assignedAgent = agents[currentIndex];

// Advance round-robin
staticData.agentIndexes[category] =
  (currentIndex + 1) % agents.length;

// Return result
return {
  ...item,
  lead_status: "New",
  assigned_agent: assignedAgent,
  assignment_category: category,
  assignment_timestamp: new Date().toISOString()
};

// Get the current date and time
const now = new Date();

// Create a new Date object to represent "7 days ago"
const sevenDaysAgo = new Date();

// Subtract 7 days from today's date
sevenDaysAgo.setDate(now.getDate() - 7);

// Filter all incoming items to keep only those
// whose createdTime is within the last 7 days
const recentRecords = items.filter(item => {
  // Parse the Airtable createdTime string into a Date object
  const createdTime = new Date(item.json.createdTime);

  // Keep the record if it was created on or after 7 days ago
  return createdTime >= sevenDaysAgo;
});

// Return a single item containing the count
// of records created within the last 7 days
return [
  {
    json: {
      count: recentRecords.length
    }
  }
];

// Get the current date and time
const now = new Date();

// Create a Date object representing 7 days ago
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(now.getDate() - 7);

// Filter incoming Airtable records
const recentRecords = items.filter(item => {
  // Convert Airtable createdTime (ISO string) to a Date object
  const createdTime = new Date(item.json.createdTime);

  // Keep the record only if it was created within the last 7 days
  return createdTime >= sevenDaysAgo;
});

// Return the filtered records
return recentRecords;

